/* CBMC stub models for the C standard-library allocation functions.

   `malloc` is intentionally left as a body-less declaration: CBMC's
   contract-enforcement (`goto-instrument --enforce-contract`) inlines any
   `malloc` that has a body, which moves the heap-allocation tracking into the
   inlined callee's scope where it is invalidated at the callee's return -- so
   writes to the returned buffer are then reported as "not assignable".  With no
   body the `malloc` call survives into the assigns instrumentation, which
   recognizes calls named "malloc" and tracks the returned object as assignable
   in the *caller's* frame.  CBMC supplies the actual allocation model for the
   body-less `malloc` at the final solving stage. */

/* FUNCTION: malloc */

void *malloc(__CPROVER_size_t size);

/* FUNCTION: free */

/* `__CPROVER_deallocate`'s builtin body assigns to a `__CPROVER_bool` temp that
   has no byte size, which crashes the contract-enforcement assigns
   instrumentation (instrument_spec_assigns create_car_expr: "no definite size
   for lvalue target ... __CPROVER_deallocate").  Since the verification pipeline
   runs no memory-leak / use-after-free checks, modeling `free` as a no-op is
   sound for the properties we check and avoids pulling that builtin into the
   model. */
void free(void *ptr)
{
    (void)ptr;
}

